&lt;h3 id=&#34;order-by字句&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#order-by字句&#34;&gt;#&lt;/a&gt; order by 字句&lt;/h3&gt;
&lt;figure class=&#34;highlight sql&#34;&gt;&lt;figcaption data-lang=&#34;SQL&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;SELECT&lt;/span&gt; column1&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; column2&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;FROM&lt;/span&gt; table_name&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;ORDER&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;BY&lt;/span&gt; column1&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; column2&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;ASC&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;|&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;DESC&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;实力&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#实力&#34;&gt;#&lt;/a&gt; 实力&lt;/h2&gt;
&lt;figure class=&#34;highlight sql&#34;&gt;&lt;figcaption data-lang=&#34;SQL&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;select&lt;/span&gt;  &lt;span class=&#34;token keyword&#34;&gt;DISTINCT&lt;/span&gt; SNO &lt;span class=&#34;token keyword&#34;&gt;FROM&lt;/span&gt; SPJ ；&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;连接查询&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#连接查询&#34;&gt;#&lt;/a&gt; 连接查询&lt;/h2&gt;
&lt;figure class=&#34;highlight sql&#34;&gt;&lt;figcaption data-lang=&#34;SQL&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;select&lt;/span&gt; CITY&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;JNO &lt;span class=&#34;token keyword&#34;&gt;FROM&lt;/span&gt; S&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;SPJ &lt;span class=&#34;token keyword&#34;&gt;WHERE&lt;/span&gt; spj&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;SNO&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;S&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;SNO&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;分为 自身 和自然 外连接 &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;select&lt;/span&gt; CITY&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;SPJ&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;SNO&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;S&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;SNO &lt;span class=&#34;token keyword&#34;&gt;FROM&lt;/span&gt; S&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;SPJ &lt;span class=&#34;token keyword&#34;&gt;WHERE&lt;/span&gt; spj&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;SNO&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;S&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;SNO &lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;select&lt;/span&gt; SPJ&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;CITY &lt;span class=&#34;token keyword&#34;&gt;FROM&lt;/span&gt; S&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;SPJ &lt;span class=&#34;token keyword&#34;&gt;WHERE&lt;/span&gt; spj&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;SNO&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;S&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;SNO &lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;联合查询集合查询&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#联合查询集合查询&#34;&gt;#&lt;/a&gt; 联合查询 (集合查询)&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;当您使用  &lt;code&gt;UNION&lt;/code&gt;  操作符时，确保两个查询选择的列的数据类型兼容，并且两个查询的列数相同&lt;/p&gt;
&lt;/blockquote&gt;
&lt;figure class=&#34;highlight sql&#34;&gt;&lt;figcaption data-lang=&#34;SQL&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;-- 看看实力&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;select&lt;/span&gt; qty &lt;span class=&#34;token keyword&#34;&gt;from&lt;/span&gt; spj &lt;span class=&#34;token keyword&#34;&gt;union&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;select&lt;/span&gt; sNO &lt;span class=&#34;token keyword&#34;&gt;FROM&lt;/span&gt; S&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;交集查询&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#交集查询&#34;&gt;#&lt;/a&gt; 交集查询&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;`intersect&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h2 id=&#34;差集查询&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#差集查询&#34;&gt;#&lt;/a&gt; 差集查询&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;`EXCEPT&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h2 id=&#34;嵌套查询&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#嵌套查询&#34;&gt;#&lt;/a&gt; 嵌套查询&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;知道一些运算符号就可以&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h4 id=&#34;in&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#in&#34;&gt;#&lt;/a&gt; IN&lt;/h4&gt;
&lt;blockquote&gt;
&lt;p&gt;在 where 子句中找到  IN  后接 select  查询 找到的列 在&lt;/p&gt;
&lt;/blockquote&gt;
&lt;figure class=&#34;highlight sql&#34;&gt;&lt;figcaption data-lang=&#34;SQL&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;SELECT&lt;/span&gt; QTY &lt;span class=&#34;token keyword&#34;&gt;FROM&lt;/span&gt; spj &lt;span class=&#34;token keyword&#34;&gt;WHERE&lt;/span&gt; QTY &lt;span class=&#34;token operator&#34;&gt;IN&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;SELECT&lt;/span&gt; QTY &lt;span class=&#34;token keyword&#34;&gt;FROM&lt;/span&gt; SPJ &lt;span class=&#34;token keyword&#34;&gt;WHERE&lt;/span&gt; QTY &lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;300&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;-- IN 之后需要包在括号里面&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h4 id=&#34;一对多&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#一对多&#34;&gt;#&lt;/a&gt; 一对多&lt;/h4&gt;
&lt;blockquote&gt;
&lt;p&gt;all 和 any 两个关键字&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;= &amp;gt; &amp;lt; &amp;lt;= !=&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/blockquote&gt;
&lt;h4 id=&#34;多对多&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#多对多&#34;&gt;#&lt;/a&gt; 多对多&lt;/h4&gt;
&lt;blockquote&gt;
&lt;p&gt;使用 EXISTS 关键字&lt;br /&gt;
 where 后使用 EXISTS 查询结果   感觉类似于连接查询&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h1 id=&#34;增加数据&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#增加数据&#34;&gt;#&lt;/a&gt; 增加数据&lt;/h1&gt;
